INSERT INTO Blog (title, content, image, author, tags, createdAt, updatedAt) VALUES 
('السياحة العلاجية: أفضل الوجهات للاستجمام وتجديد الطاقة', 'في عالمنا المتسارع، نحتاج جميعاً إلى وقفة لاستعادة التوازن الجسدي والنفسي.\n\n- **البحر الميت، الأردن**: العلاج الطبيعي بالأملاح والمعادن النادرة.\n- **بادن بادن، ألمانيا**: الحمامات الحرارية والينابيع الشافية.\n- **كيرالا، الهند**: مهد علاج "الأيورفيدا" التقليدي وسط الطبيعة الخضراء.\n\nالميراج توفر لك برامج استشفائية متكاملة تشمل الفحوصات الطبية وجلسات الاسترخاء في أفخم المنتجعات العالمية.', 'https://images.unsplash.com/photo-1544161515-4ab6ce6db874?q=80&w=1200&auto=format&fit=crop', 'أخصائي رحلات الاستجمام', 'سياحة علاجية, صحة, استرخاء', NOW(), NOW()),
('نصائح الخبراء: كيف تخطط لرحلة شهر عسل ملكية؟', 'رحلة العمر تستحق تخطيطاً استثنائياً. إليك الخطوات التي نتبعها في الميراج لتصميم شهر عسل لا يُنسى:\n\n1. **الميزانية الذكية**: نساعدك في تخصيص ميزانيتك للأمور التي تهمك حقاً.\n2. **المفاجآت الخاصة**: ترتيب عشاء رومانسي على الشاطئ أو رحلة خاصة بطائرة هليكوبتر.\n3. **التوثيق**: نوفر لك مصورين محترفين لتوثيق أجمل لحظاتكم.\n\nتواصل معنا الآن، ودعنا نحول أحلامك إلى حقيقة ملموسة في أجمل بقاع الأرض.', 'https://images.unsplash.com/photo-1519225421980-715cb0215aed?q=80&w=1200&auto=format&fit=crop', 'قسم كبار الشخصيات', 'شهر عسل, نصائح, رفاهية', NOW(), NOW());
INSERT INTO Package (title, description, image, price, oldPrice, discount, duration, location, category, isFeatured, createdAt, updatedAt) VALUES 
('رحلة ساحل الأمالفي الإيطالي - سحر المتوسط', 'استكشف أجمل السواحل في العالم. رحلة مخصصة لمحبي الطبيعة والمناظر الخلابة في جنوب إيطاليا، تشمل زيارة بوسيتانو ورافيلو وجزيرة كابري.', 'https://images.unsplash.com/photo-1533104816931-20fa691ff6ca?q=80&w=1200&auto=format&fit=crop', 9800, 11000, 10, '7 أيام / 6 ليالي', 'إيطاليا', 'packages', 0, NOW(), NOW()),
('مغامرة سفاري كينيا - قلب إفريقيا النابض', 'رحلة العمر لمحبي الحياة البرية. استمتع بمشاهدة "الخمسة الكبار" في محمية ماساي مارا مع إقامة في مخيمات فاخرة وسط الطبيعة.', 'https://images.unsplash.com/photo-1516426122078-c23e76319801?q=80&w=1200&auto=format&fit=crop', 12400, NULL, NULL, '6 أيام / 5 ليالي', 'كينيا', 'packages', 1, NOW(), NOW()),
('رحلة عائلية في ديزني لاند باريس', 'اجعل أحلام أطفالك حقيقة في عالم ديزني الساحر. إقامة داخل فنادق ديزني مع تذاكر دخول غير محدودة للمتنزهات لمدة 4 أيام.', 'https://images.unsplash.com/photo-1562601149-10667367332c?q=80&w=1200&auto=format&fit=crop', 8900, 10500, 15, '4 أيام / 3 ليالي', 'فرنسا', 'packages', 0, NOW(), NOW());
